"""Local regression proofs for the documented VAmPI authorization boundaries.

The fixture's pinned runtime dependencies need not be installed for this proof:
the tests execute the repository's handler functions with synthetic local doubles.
"""

import ast
import json
from pathlib import Path
from types import SimpleNamespace
import unittest
import warnings


ROOT = Path(__file__).resolve().parents[1]


def load_handler(relative_path, function_name, globals_):
    """Compile one handler from the repository with controlled local globals."""
    path = ROOT / relative_path
    with warnings.catch_warnings():
        warnings.simplefilter("ignore", SyntaxWarning)
        tree = ast.parse(path.read_text(encoding="utf-8"), filename=str(path))
    function = next(
        node
        for node in tree.body
        if isinstance(node, ast.FunctionDef) and node.name == function_name
    )
    module = ast.fix_missing_locations(ast.Module(body=[function], type_ignores=[]))
    namespace = dict(globals_)
    exec(compile(module, str(path), "exec"), namespace)
    return namespace[function_name]


class SyntheticResponse:
    def __init__(self, body, status, mimetype=None):
        self.body = body
        self.status_code = status
        self.mimetype = mimetype

    def get_json(self):
        return json.loads(self.body)


class QueryResult:
    def __init__(self, value):
        self.value = value

    def first(self):
        return self.value


def error_message_helper(message):
    if isinstance(message, dict):
        message = message["error"]
    return json.dumps({"status": "fail", "message": message})


class BookAuthorizationTests(unittest.TestCase):
    def setUp(self):
        self.owner = SimpleNamespace(username="owner")
        self.attacker = SimpleNamespace(username="attacker")
        self.book = SimpleNamespace(
            book_title="victim-book",
            secret_content="victim-secret",
            user=self.owner,
        )

    def handler_for(self, authenticated_username):
        users = {"owner": self.owner, "attacker": self.attacker}
        book = self.book

        class UserQuery:
            def filter_by(self, **filters):
                return QueryResult(users.get(filters.get("username")))

        class BookQuery:
            def filter_by(self, **filters):
                matches_title = (
                    "book_title" not in filters
                    or filters["book_title"] == book.book_title
                )
                matches_owner = "user" not in filters or filters["user"] is book.user
                return QueryResult(book if matches_title and matches_owner else None)

        class User:
            query = UserQuery()

        class Book:
            query = BookQuery()

        request = SimpleNamespace(headers={"Authorization": "Bearer [redacted]"})
        return load_handler(
            "api_views/books.py",
            "get_by_title",
            {
                "Book": Book,
                "User": User,
                "Response": SyntheticResponse,
                "error_message_helper": error_message_helper,
                "json": json,
                "request": request,
                "token_validator": lambda _header: {"sub": authenticated_username},
                "vuln": True,
            },
        )

    def test_non_owner_cannot_retrieve_book_secret(self):
        response = self.handler_for("attacker")("victim-book")

        self.assertEqual(404, response.status_code)
        self.assertEqual(
            {"status": "fail", "message": "Book not found!"},
            response.get_json(),
        )
        self.assertNotIn("victim-secret", response.body)

    def test_owner_retains_existing_success_contract(self):
        response = self.handler_for("owner")("victim-book")

        self.assertEqual(200, response.status_code)
        self.assertEqual(
            {
                "book_title": "victim-book",
                "secret": "victim-secret",
                "owner": "owner",
            },
            response.get_json(),
        )


class UserDeletionAuthorizationTests(unittest.TestCase):
    def handler_for(self, is_admin, deleted):
        authenticated_user = SimpleNamespace(username="requester", admin=is_admin)

        class UserQuery:
            def filter_by(self, **filters):
                value = authenticated_user if filters.get("username") == "requester" else None
                return QueryResult(value)

        class User:
            query = UserQuery()

            @staticmethod
            def delete_user(username):
                deleted.append(username)
                return 1

        request = SimpleNamespace(headers={"Authorization": "Bearer [redacted]"})
        return load_handler(
            "api_views/users.py",
            "delete_user",
            {
                "User": User,
                "Response": SyntheticResponse,
                "error_message_helper": error_message_helper,
                "json": json,
                "request": request,
                "token_validator": lambda _header: {"sub": "requester"},
            },
        )

    def test_non_admin_cannot_delete_user(self):
        deleted = []
        response = self.handler_for(False, deleted)("target")

        self.assertEqual(401, response.status_code)
        self.assertEqual(
            {"status": "fail", "message": "Only Admins may delete users!"},
            response.get_json(),
        )
        self.assertEqual([], deleted)

    def test_admin_retains_existing_delete_contract(self):
        deleted = []
        response = self.handler_for(True, deleted)("target")

        self.assertEqual(200, response.status_code)
        self.assertEqual(
            {"status": "success", "message": "User deleted."},
            response.get_json(),
        )
        self.assertEqual(["target"], deleted)


if __name__ == "__main__":
    unittest.main()

